mapper.select:
SELECT B1.* FROM ( SELECT A1.* -- , ROW_NUMBER() OVER(ORDER BY A1.insertDt DESC) AS PAGEINDEX , ROW_NUMBER() OVER( ORDER BY
A1.insertDt DESC
CAST(A1.${sortColumn} AS INTEGER) ${order}
A1.${sortColumn} ${order}
) AS PAGEINDEX FROM ( SELECT info.BUSINESS_TYPE_CD AS businessTypeCd,
info.BUSINESS_PHASE AS bussinessTypeNm, info.DISTRIBUTE_TYPE_CD AS distributeTypeCd,
info.file_type AS distributeTypeNm, info.DRAWING_NO AS drawingNo, info.DRAWING_NM AS drawingNm, info.REV_NO AS revNo, info.CUSTOMER_REVISION AS customerRevision, info.CURRENT_PAGE_NO AS currentPageNo, info.TOTAL_PAGE_NO AS totalPageNo, info.INSERT_UID AS insertUid, info.OBJECT_ID AS objectId, info.INSERT_USER_NM AS insertUserNm, info.DRAWING_TYPE AS drawingType, updateUser.USER_NM AS updateUserNm, info.INSERT_DEPT_NM AS insertDeptNm, info.STD_GAPP_DT AS stdGappDt, info.CHANGE_GAPP_DT AS changeGappDt, info.ECN_NO AS ecnNo, ecnInsert.USER_NM AS ecnUserNm, '' AS companyNm, purchaser.USER_NM AS purchaserUserNm, info.PURCHASER_UID AS purchaserUid, info.BUSINESS_AREA_CD AS businessAreaCd, FN_GET_CD_NM('businessAreaCdAll', info.BUSINESS_AREA_CD, 'ko') AS businessAreaNm, info.PROTECT_YN AS protectYn, info.PROTECT_YN AS protectYnView, info.UPDATE_DT AS updateDt, info.INSERT_DT AS insertDt, info.CREATE_DATE AS createDate, info.INTERFACE_DT AS interfaceDt, '' AS companyCd, info.PRODUCT_CD AS productCd,
info.MODEL_CODE AS productNm, 1 AS fileNo, info.FILE_NM AS fileNm, info.FILE_PATH_NM AS filePath, info.ORG_FILE_NM AS fileViewNm, info.ORG_FILE_NM AS orgFileNm, info.FILE_SIZE AS fileSize, info.ECN_TITLE AS ecnTitle, info.ECN_VENDOR_USER AS ecnVendorUser, info.VALID_TYPE AS validType, info.DISTRIBUTION_POINT AS distributionPoint, info.approvaldate AS approvalDate, info.approver AS approver, COALESCE(info.PROCESSING_STATUS, '') AS processingStatus, CASE WHEN info.status = '승인완료' THEN '승인완료' WHEN COALESCE(NULLIF(TRIM(info.approver), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.approver, ' ', ''), ',') AS ap(token) WHERE COALESCE(NULLIF(TRIM(ap.token), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(COALESCE(info.approved_users, info.status, ''), ' ', ''), ',') AS au(token) WHERE split_part(TRIM(au.token), '|', 1) = ap.token ) ) AND COALESCE(NULLIF(TRIM(info.reviewerUser), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(info.reviewerUser, ' ', ''), ',') AS rv(token) WHERE COALESCE(NULLIF(TRIM(rv.token), ''), '') <> '' AND NOT EXISTS ( SELECT 1 FROM regexp_split_to_table(REPLACE(COALESCE(info.approved_users, info.status, ''), ' ', ''), ',') AS au(token) WHERE split_part(TRIM(au.token), '|', 1) = rv.token ) ) THEN '승인완료' ELSE '승인진행중' END AS status, info.coPublisher AS coPublisher, info.reviewerUser AS reviewerUser, '' AS checkSum, ROW_NUMBER() OVER ( PARTITION BY info.DRAWING_NO ORDER BY COALESCE(info.CREATE_DATE, info.INSERT_DT) DESC, info.INSERT_DT DESC ) AS rn FROM DOCS_DRAWING info LEFT JOIN DOCS_USER insertUser ON info.INSERT_UID = insertUser.USER_ID LEFT JOIN DOCS_USER updateUser ON info.UPDATE_UID = updateUser.USER_ID
LEFT JOIN DOCS_USER purchaser ON purchaser.USER_ID = info.PURCHASER_UID LEFT JOIN DOCS_USER ecnInsert ON ecnInsert.USER_ID = info.ecn_insert_uid WHERE 1=1
AND info.DELETED_YN = 'N'
AND info.BUSINESS_TYPE_CD = #{businessTypeCd}
AND info.BUSINESS_AREA_CD LIKE '%' || #{businessAreaCd} || '%'
AND info.DRAWING_NO = UPPER(TRIM(#{drawingNo}))
AND info.DRAWING_NO LIKE '%' || UPPER(TRIM(#{drawingNo})) || '%'
AND EXISTS ( SELECT 1 FROM DOCS_DRAWING_TREE docTree , DOCS_DRAWING_TREE selectedTree WHERE TRIM(docTree.TREE_CD) = TRIM(info.TREE_CD) AND TRIM(selectedTree.TREE_CD) = TRIM(#{drawingTreeCd}) AND docTree.TREE_PATH LIKE selectedTree.TREE_PATH || '%' )
AND info.DRAWING_NM LIKE '%' || #{drawingNm} || '%'
AND info.PURCHASER_UID = #{purchaserUid}
AND ( info.FILE_TYPE = #{distributeTypeCd} OR info.DISTRIBUTE_TYPE_CD = #{distributeTypeCd} )
AND info.ECN_NO LIKE '%' || UPPER(TRIM(#{ecnNo})) || '%'
AND 1=1
AND info.model_code LIKE '%' || UPPER(TRIM(#{productCd})) || '%'
AND info.INSERT_UID = #{insertUid}
AND info.VALID_TYPE IS NULL
AND info.VALID_TYPE = 'N'
AND info.INTERFACE_DT BETWEEN TO_DATE(#{interfaceStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{interfaceEndDt}, 'YYYY-MM-DD') + INTERVAL '1' DAY
-- AND DECODE(LENGTH(info.REV_NO),1,info.REV_NO||'Z',info.REV_NO) = ( AND DECODE(LENGTH(info.CUSTOMER_REVISION),1,info.CUSTOMER_REVISION||'Z',info.CUSTOMER_REVISION) = ( SELECT MAX(DECODE(LENGTH(sub_info.CUSTOMER_REVISION),1,sub_info.CUSTOMER_REVISION||'Z',sub_info.CUSTOMER_REVISION)) FROM DOCS_DRAWING sub_info WHERE sub_info.DRAWING_NO = info.DRAWING_NO AND sub_info.CURRENT_PAGE_NO = info.current_page_no )
AND (
(DRAWING_NO LIKE '%' || UPPER(TRIM(#{drawingInfo.drawingNo})) || '%')
)
AND (
(DRAWING_NO = UPPER(TRIM(#{drawingInfo.drawingNo})))
)
ORDER BY info.INSERT_DT DESC, info.CURRENT_PAGE_NO
ORDER BY ${sortColumn} ${order}
) A1
WHERE rn = 1
) B1 WHERE 1=1
AND PAGEINDEX <= #{end}
AND PAGEINDEX >= #{start}

SELECT OBJECT_ID
FROM DOCS_DRAWING
WHERE OBJECT_ID = #{objectId}

mapper.update:
UPDATE DOCS_DRAWING
   SET DELETED_YN = 'Y',
       UPDATE_DT = CURRENT_TIMESTAMP
 WHERE DRAWING_NO = #{drawingNo}
   AND OBJECT_ID != #{objectId}
   AND COALESCE(DELETED_YN, 'N') = 'N'

UPDATE DOCS_DRAWING
SET APPROVED_USERS = #{approvedUsers}
WHERE OBJECT_ID = #{objectId}
  AND COALESCE(DELETED_YN, 'N') = 'N'

UPDATE DOCS_DISTRIBUTION_APPROVAL_DETAIL
   SET APPROVAL_STATUS = 'APPROVAL',
       APPROVAL_DT = CURRENT_TIMESTAMP,
       UPDATE_DT = CURRENT_TIMESTAMP
 WHERE OBJECT_ID = #{objectId}
   AND OBJECT_TYPE = #{objectType}
   AND (
       USER_NM = #{userNm}
       OR USER_ID = #{userId}
       OR USER_NM = #{userId}
       OR USER_ID = #{userNm}
   )
   AND COALESCE(APPROVAL_STATUS, 'WAIT') != 'APPROVAL'
